import React from "react";
import PropTypes from "prop-types";
import classNames from "classnames";

/**
 * Badges are really great for labels and count values.
 */
const Badge = props => {
  let {
    tag: Tag = "span",
    className,
    theme = "primary",
    pill = false,
    outline = false,
    ...attrs
  } = props;

  const classes = classNames(
    className,
    "bs-badge",
    theme && !outline && `bs-badge-${theme}`,
    outline && `bs-badge-outline-${theme}`,
    pill && "bs-badge-pill"
  );

  Tag = attrs.href && Tag === "span" ? "a" : Tag;

  return <Tag {...attrs} className={classes} />;
};

Badge.propTypes = {
  /**
   * The children nodes.
   */
  children: PropTypes.node,
  /**
   * The class name.
   */
  className: PropTypes.string,
  /**
   * The theme color.
   */
  theme: PropTypes.string,
  /**
   * Whether it should be outlined, or not.
   */
  outline: PropTypes.bool,
  /**
   * Whether it should be a pill, or not.
   */
  pill: PropTypes.bool,
  /**
   * The component tag.
   */
  tag: PropTypes.oneOfType([PropTypes.func, PropTypes.string])
};

export default Badge;
